#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

__global__ void bmm_with_bias_relu_kernel(const float* A, const float* B, float* C, const float* bias, int batch_size, int m, int k, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int row = idx / n;
    int col = idx % n;

    if (row >= m || col >= n) {
        return;
    }

    float sum = 0.0f;
    for (int i = 0; i < k; ++i) {
        sum += A[row * k + i] * B[i * n + col];
    }

    C[row * n + col] = max(sum + bias[col], 0.0f);
}

std::vector<at::Tensor> bmm_with_bias_relu(const at::Tensor& A, const at::Tensor& B, const at::Tensor& bias) {
    auto options = A.options();
    auto C = at::empty_like(B, options);

    dim3 threads(256);
