    }

    if (bias != nullptr) {
        sum += bias[col];
    }

    C[row * M + col] = sum;
}

static auto matmul_epilogue_wrapper = torch::dispatch::singleton_context().registerOp(
    "matmul_epilogue",
    [](at::Tensor& A, at::Tensor& B, at::optional<at::Tensor> bias) {
