#include <torch/torch.h>
#include <vector>

void fused_conv_bias_relu(const at::Tensor& input, const at::Tensor& weight, const at::Tensor& bias, at::Tensor& output) {
    // Get tensor dimensions
    int N = input.size(0);
    int C_in = input.size(1);
    int H_in = input.size(2);
    int W_in = input.size(3);
    int C_out = weight.size(0);
    int K = weight.size(2);

    // Perform convolution and bias addition in a fused manner
    #pragma omp parallel for collapse(2)
    for (int n = 0; n < N; ++n) {
        for (int c_out = 0; c_out < C_out; ++c_out) {
            for (int h_out = 0; h_out < H_in - K + 1; ++h_out) {
                for (int w_out = 0; w_out < W_in - K + 1; ++w_out) {
                    float sum = 0.0f;
                    for (int c_in = 0; c_in < C_in; ++c_in) {
                        for (int k_h = 0; k_h < K; ++k_h) {
                            for (int k_w = 0; k_w < K; ++k_w) {
                                sum += input[n][c_in][h_out + k_h][w_out + k_w] * weight[c_out][c_in][k_h][k_w];
                            }
                        }
                    }
                    output[n][c_out][h_out][w_out] = sum + bias[c_out].item<float>();
                }
            }
        }
