    // Perform convolution and bias addition in a fused manner
    int n = blockIdx.x / ((H_in - K + 1) * (W_in - K + 1));
    int hw_idx = blockIdx.x % ((H_in - K + 1) * (W_in - K + 1));
    int h_out = hw_idx / (W_in - K + 1);
    int w_out = hw_idx % (W_in - K + 1);

    float sum = 0.0f;
    for (int c_in = 0; c_in < C_in; ++c_in) {
        for (int k_h = 0; k_h < K; ++k_h) {
            for (int k_w = 0; k_w < K; ++k_w) {
                int ih = h_out + k_h;
                int iw = w_out + k_w;
                sum += input[n][c_in][ih][iw] * weight[c_out][c_in][k_h][k_w];
            }
