#include <cuda_runtime.h>

__global__ void fused_matmul_relu_kernel(
    const float* input, const float* weight, const float* bias,
    float* output, int batch_size, int in_features, int out_features, float subtract_value, float multiply_value) {
    int tid = threadIdx.x;
    int bid = blockIdx.x;

    extern __shared__ float s[];
    float* s_input = s + tid * in_features;
    float* s_weight = s + tid * out_features;

    // Load data into shared memory
    s[tid] = input[bid * in_features + tid];
    s_input[tid] = weight[tid * out_features + tid];
    s_weight[tid] = weight[tid * out_features + tid];

    __syncthreads();

    float sum = 0.0f;
    for (int k = 0; k < in_features; ++k) {
        sum += s_input[k] * s_weight[k];
    }

    float val = sum - subtract_value;
    val *= multiply_value;
    val = val > 0 ? val : 0; // ReLU

    // Store result back to global memory
    output[bid * out_features + tid] = val;
}

