    const int blocks_per_grid = (batch_size + threads_per_block - 1) / threads_per_block;

    fused_matmul_relu_kernel<<<blocks_per_grid, threads_per_block, threads_per_block * sizeof(float)>>>(
        input.data_ptr<float>(), weight.data_ptr<float>(), bias.data_ptr<float>(),
        output.data_ptr<float>(), batch_size, in_features, out_features, subtract_value, multiply_value);

